import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Загрузка логов","description":"Как загрузить логи для устранения проблем.","frontmatter":{"title":"Загрузка логов","description":"Как загрузить логи для устранения проблем.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.1/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.1/translated/ru_ru/players/troubleshooting/uploading-logs.md","lastUpdated":1761424914000}`);var a={name:`ru_ru/1.21.1/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Загрузка логов <a class="header-anchor" href="#h1" aria-label="Permalink to “Загрузка логов”">​</a></h1><p>При устранении проблем часто бывает необходимо предоставить логи, которые помогут определить причину проблемы.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Почему я должен загружать журналы? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Почему я должен загружать журналы?”">​</a></h2><p>Загрузка логов позволяет другим людям в устранении проблем гораздо быстрее, чем просто вставка логов в сообщение в чате или на форуме. Это также позволяет вам делиться своими логами с другими людьми без необходимости копировать и вставлять их.</p><p>Некоторые сайты для текстов также предоставляют подсветку синтаксиса для логов, что облегчает их чтение, а также они могут подвергать цензуре конфиденциальную информацию, например, системную информацию или ваш ник.</p><h2 id="crash-reports" tabindex="-1">Краш-репорты <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Краш-репорты”">​</a></h2><p>Краш-репорты генерируются автоматически при краше игры. Они содержат только информацию о краше, а не фактические логи игры. Они находятся в папке <code>crash-reports</code> в папке игры.</p><p>Дополнительные сведения о краш-репортах смотрите <a href="./crash-reports">в гайде о краш-репортах</a>.</p><h2 id="locating-logs" tabindex="-1">Нахождение логов <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Нахождение логов”">​</a></h2><p>Этот гайд относится к официальному лаунчеру (или же &quot;ванильный лаунчер&quot;). Для сторонних лаунчеров вам следует ознакомиться с их документацией.</p><p>Логи находятся в папке <code>logs</code> в папке игры, которую можно найти в следующих местах, в зависимости от вашей операционной системы:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Файл с последними логами называется <code>latest.log</code>, предыдущие логи называются по шаблону <code>гггг-мм-дд_номер.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Загрузка логов <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Загрузка логов”">​</a></h2><p>Логи могут быть загружены в различные сервисы, такие как:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};